// Bouw een Telegram-vriendelijke Markdown digest.
const s = $input.first().json;
const lines = [];
lines.push(`*Lead Dashboard — ${s.date}*`);
lines.push('');
if (s.paused) lines.push(`🛑 *PAUZE*: ${s.pauseReason}`);
lines.push(`📧 Verstuurd: *${s.sent.total}* (delivered ${s.sent.delivered}, bounced ${s.sent.bounced}, klacht ${s.sent.complained})`);
if (s.sent.bouncedPct > 2) lines.push(`⚠️  Bounce rate ${s.sent.bouncedPct}% (>2% = alert)`);
if (s.sent.complainedPct > 0.1) lines.push(`⚠️  Complaint rate ${s.sent.complainedPct}% (>0.1% = alert)`);
lines.push(`📋 Queue: ${s.queue.pending} pending review, ${s.queue.approved} ready-to-send`);
lines.push(`💰 Kost: €${s.cost.totalEur.toFixed(3)} / €${s.cost.budgetEur} (${s.cost.pct}%)`);
lines.push(`🌡️ Warmup: ${s.warmup.stage} (${s.warmup.maxSendsToday}/dag)`);
if (s.topRejectReasonsLast7Days?.length) {
  lines.push('');
  lines.push('*Top reject redenen (7d):*');
  for (const r of s.topRejectReasonsLast7Days) lines.push(`  • ${r.reason}: ${r.count}`);
}
return [{ json: { text: lines.join('\n'), parse_mode: 'Markdown', summary: s } }];
